module top_module(
	input clock_i,
	input D,
	input S,
	input R,
	output Q
);reg not_out;	// Need to reset before use, default is powerup high

	assign Q = not_out;

	always @(posedge clock_i)
	begin
		if( S ) 
			not_out <= 1'b1;
		else if( R )
			not_out <= 1'b0;
		else
			not_out <= D;
	end
endmodule
